const raw = $json.text;

// 1. Remove markdown
const cleaned = raw.replace(/```json|```/g, '').trim();

// 2. Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error("Invalid JSON from LLM");
}

// 3. Remove "output" wrapper if exists
const finalData = parsed.output ? parsed.output : parsed;

return [{ json: finalData }];

