// 1. Get the structured email draft from the previous node
const emailDraft = $input.first().json.output

// 2. Access the candidate's name from your "CV Parser" node
// Replace 'CV_Parser' with the actual name of your parsing node
const candidateName = $('log candidate').first().json.full_name

// 3. Define the sender's name (could also be dynamic from an environment variable) and Company name
const senderName = "The Recruitment Team";
const companyName = "oTechQ-tech.Corp"

// 4. Perform the string replacement
let updatedBody = emailDraft.email_body.replace(/\[USER_NAME\]/g, candidateName);
updatedBody = updatedBody.replace(/\[SENDER_NAME\]/g, senderName);
updatedBody = updatedBody.replace(/\[COMPANY_NAME\]/g, companyName)

let updatedSubject = emailDraft.subject_line.replace(/\[COMPANY_NAME\]/g, companyName)

// 5. Return the updated JSON
return {
  subject_line: updatedSubject,
  email_body: updatedBody,
  recipient_email: $('log candidate').first().json.email
};
